INSERT INTO `products` VALUES ('03f1141e-c419-48d4-884d-8dfa91304ad8','Case Xigmatek Cloud M DGT Black (EN49859) - No Fan',1090000,'<p>THÔNG SỐ KỸ THUẬT</p>\n<div>\n<table border=\"1\">\n<tbody>\n<tr>\n<td>Khe cắm mở rộng</td>\n<td>4 slots</td>\n</tr>\n<tr>\n<td>Chất liệu</td>\n<td>Thép, Kính cường lực</td>\n</tr>\n<tr>\n<td>Phân loại</td>\n<td>Mid Tower</td>\n</tr>\n<tr>\n<td>Cổng kết nối</td>\n<td>1 x USB 3.0/1 x USB 2.0/1 x HD Audio</td>\n</tr>\n<tr>\n<td>Màu sắc</td>\n<td>ĐEN</td>\n</tr>\n<tr>\n<td>Fan</td>\n<td>Trên (Top): 3 x 120mm hoặc 2 x 140mm; Bên hông (Side): 2 x 120mm hoặc 2 x 140mm; Dưới (Bottom): 3 x 120mm hoặc 2 x 140mm; Sau (Rear): 1 x 120mm</td>\n</tr>\n<tr>\n<td>Khe gắn ổ cứng</td>\n<td>1 x 2.5\" và 1 x 3.5\" hoặc 2 x 2.5\"</td>\n</tr>\n<tr>\n<td>Mainboard hỗ trợ</td>\n<td>Micro ATX (hỗ trợ main Back Plug)/Mini ITX</td>\n</tr>\n<tr>\n<td>Kích thước</td>\n<td>420 x 285 x 382mm</td>\n</tr>\n<tr>\n<td>Hỗ trợ VGA</td>\n<td>Chiều dài tối đa 400mm</td>\n</tr>\n<tr>\n<td>Hỗ trợ tản nhiệt CPU</td>\n<td>Chiều cao tối đa 175mm</td>\n</tr>\n<tr>\n<td>Hỗ trợ tản nhiệt nước</td>\n<td>Trên (Top): 360/280/240mm; Bên hông (Side): 280/240mm</td>\n</tr>\n<tr>\n<td>Hỗ trợ PSU</td>\n<td>Chiều dài tối đa 220mm</td>\n</tr>\n<tr>\n<td>Bảo hành</td>\n<td>12 tháng</td>\n</tr>\n</tbody>\n</table>\n</div>\n<div> </div>',10,'/uploads/images/6e4b6a91-c417-46b1-b0d6-e42207b090d2.jpg,/uploads/images/34ac766a-5189-42c9-98b8-3463bbbdf47a.jpg,/uploads/images/610e90d9-0bf7-40cc-8be2-fa3403e939f6.jpg,/uploads/images/e2c6973e-d6e9-4b88-9caf-d7a8372f1d11.jpg,/uploads/images/f7dbd237-22aa-40af-811a-3b5d6e077cd5.jpg,/uploads/images/30803008-1539-475a-a551-d9d24628cf75.jpg','751258d9-4091-4ce5-9b7e-ffb7a8513f34',100,'case','active','2026-05-08 20:40:22','2026-05-08 20:40:22',NULL),('0956fa48-dce3-477d-9d1e-5e5cb59166d0','RAM Adata XPG Lancer Blade White 32GB (2x16GB) DDR5 5600MHz (AX5U5600C4616G-DTLABWH)',12900000,'<p>THÔNG SỐ KỸ THUẬT</p>\n<div>\n<table border=\"1\" cellpadding=\"3\">\n<tbody>\n<tr>\n<td><strong>Series</strong></td>\n<td>XPG Lancer Blade</td>\n</tr>\n<tr>\n<td><strong>Dung lượng</strong></td>\n<td>32GB (2×16GB)</td>\n</tr>\n<tr>\n<td><strong>Số lượng thanh</strong></td>\n<td>2 thanh</td>\n</tr>\n<tr>\n<td><strong>Dạng RAM</strong></td>\n<td>DIMM</td>\n</tr>\n<tr>\n<td><strong>Hỗ trợ Profile</strong></td>\n<td>Intel XMP 3.0 / AMD EXPO</td>\n</tr>\n<tr>\n<td><strong>Chuẩn kết nối</strong></td>\n<td>288-Pin</td>\n</tr>\n<tr>\n<td><strong>Điện áp</strong></td>\n<td>1.1V (dải 1.1V – 1.4V)</td>\n</tr>\n<tr>\n<td><strong>Chuẩn RAM</strong></td>\n<td>DDR5-5600 (PC5-44800)</td>\n</tr>\n<tr>\n<td><strong>Xung nhịp thực</strong></td>\n<td>2800 MHz</td>\n</tr>\n<tr>\n<td><strong>Độ trễ</strong></td>\n<td>CL46</td>\n</tr>\n</tbody>\n</table>\n</div>\n<p> </p>',12,'/uploads/images/c512e440-7fc5-4e7d-b876-d38641215fca.jpg,/uploads/images/846a2dd3-159e-48e9-9177-0c2971447a86.jpg,/uploads/images/36d21da7-baf2-4e69-bc25-0c2f570a46f4.jpg','751258d9-4091-4ce5-9b7e-ffb7a8513f34',1,'ram','active','2026-05-08 19:54:57','2026-05-08 19:54:57',NULL),('0971474a-3b05-45bf-b991-4ab64d52cf71','Ổ cứng SSD OCPC MFL-300 512GB NVMe Gen 3x4',2990000,'<div>\n<p>THÔNG SỐ KỸ THUẬT</p>\n<div>\n<table border=\"1\">\n<tbody>\n<tr>\n<td>Hãng sản xuất</td>\n<td>OCPC</td>\n</tr>\n<tr>\n<td>Model</td>\n<td>MFL-300 512GB NVMe Gen 3x4 SSDM2PCIEF512G</td>\n</tr>\n<tr>\n<td>Dung lượng ổ cứng</td>\n<td>512GB</td>\n</tr>\n<tr>\n<td>Chuẩn Cắm</td>\n<td>NVMe</td>\n</tr>\n<tr>\n<td>Tốc độ ghi</td>\n<td>3100 MB/s</td>\n</tr>\n<tr>\n<td>Tốc độ đọc</td>\n<td>2100 MB/s</td>\n</tr>\n<tr>\n<td>Kích thước ổ cứng</td>\n<td>M.2 (2280)</td>\n</tr>\n</tbody>\n</table>\n</div>\n<div> </div>\n</div>\n<div>\n<p>MÔ TẢ SẢN PHẨM</p>\n<div>\n<h2>Ổ cứng SSD OCPC MFL-300 512GB NVMe Gen 3x4 </h2>\n<h3>Đặc điểm nổi bật </h3>\n<p>Nâng cấp lưu trữ hệ thống laptop hoặc desktop của bạn với dòng sản phẩm M.2 NVMe PCIe SSD MFL-300, một SSD nhỏ gọn dạng M.2 trên giao diện kết nối SATA 6Gb/s Gen3*4. Dòng sản phẩm MFL-300 M.2 NVMe SSD là giải pháp lý tưởng để tăng tốc độ truyền dữ liệu và thời gian tải cho các trò chơi hàng ngày và công việc trên máy tính xách tay, miniPC hoặc hệ thống desktop của bạn.</p>\n<p><img src=\"https://pcmarket.vn/media/product/11883_ssd_ocpc_nvme_512g_gen_3x4_pcm_1.png\" alt=\"ssd_ocpc_nvme_512g_gen_3x4_pcm\" width=\"1000\" loading=\"lazy\" /></p>\n<p> </p>\n</div>\n<div> </div>\n</div>',10,'/uploads/images/01feee68-ec59-429a-8edc-d3341e554fad.png,/uploads/images/dd0eeb8e-1b2a-4055-8d4d-f1f10870f469.png','751258d9-4091-4ce5-9b7e-ffb7a8513f34',0,'ssd','active','2026-05-08 20:12:16','2026-05-08 20:12:16',NULL),('1a035a44-97f7-4f52-b598-1a67d214f65f','PC OFFICE Core i5 10400 - RAM 8GB- SSD 256GB- Màn hình 24 inch (Cấu hình gốc)',14000000,'<h2 align=\\\"center\\\">PC OFFICE Core i5 10400 - RAM 8GB- SSD 256GB- M&agrave;n h&igrave;nh 24 inch</h2>\n<p>PC OFFICE Core i5 10400 - RAM 8GB- SSD 256GB- M&agrave;n h&igrave;nh 24 inch&nbsp;l&agrave; một trong những cấu h&igrave;nh M&aacute;y t&iacute;nh -&nbsp;<a href=\\\"https://pcmarket.vn/pc-van-phong.html\\\"><strong>PC Văn ph&ograve;ng</strong></a>&nbsp; được&nbsp;<strong><a href=\\\"https://pcmarket.vn/\\\">Zafes Computer</a></strong>&nbsp;tối ưu về phần cứng gi&uacute;p cho kh&aacute;ch h&agrave;ng c&oacute; trải nghiệm tốt nhất trong tầm gi&aacute;. Cấu h&igrave;nh n&agrave;y th&iacute;ch hợp cho người d&ugrave;ng l&agrave;m việc chuy&ecirc;n nghiệp c&aacute;c văn bản Word, Excel, Photoshop ... giải tr&iacute; cơ bản.</p>\n<p><img src=\\\"https://pcmarket.vn/media/product/11400_dsc02846.jpg\\\" alt=\\\"\\\"></p>\n<p><strong>M&aacute;y t&iacute;nh&nbsp;<a title=\\\"Zafes Computer\\\" href=\\\"https://pcmarket.vn/\\\">Zafes Computer</a></strong>- Đơn vị cung cấp m&aacute;y t&iacute;nh - PC văn ph&ograve;ng gi&aacute; rẻ uy t&iacute;n, chất lượng với dịch vụ tốt nhất H&agrave; Nội v&agrave; to&agrave;n quốc. Ch&uacute;ng t&ocirc;i đ&atilde; đồng h&agrave;nh, cung cấp&nbsp;<strong>m&aacute;y t&iacute;nh văn ph&ograve;ng</strong>&nbsp;cho h&agrave;ng trăm&nbsp;đơn vị v&agrave; doanh nghiệp tại H&agrave; Nội v&agrave; cả nước. Đến với Zafes Computer , bạn sẽ được ch&uacute;ng t&ocirc;i tư vấn, đem lại giải ph&aacute;p&nbsp;m&aacute;y t&iacute;nh văn ph&ograve;ng với cấu h&igrave;nh ph&ugrave; hợp nhất, gi&aacute; th&agrave;nh hợp l&yacute; nhất cho tất cả kh&aacute;ch h&agrave;ng từ doanh nghiệp đến c&aacute; nh&acirc;n.</p>\n<p><img src=\\\"https://pcmarket.vn/media/product/11399_dsc02865.jpg\\\" alt=\\\"PC OFFICE - GAMING LOL, CS2, FIFA - Ryzen 5 4600G - K&egrave;m m&agrave;n h&igrave;nh 24 inch\\\"></p>\n<p>Ch&uacute;ng t&ocirc;i cam kết bất k&igrave; bộ&nbsp;PC&nbsp;văn ph&ograve;ng b&aacute;n ra đều l&agrave; c&aacute;c sản phẩm mới ch&iacute;nh h&atilde;ng 100%, c&oacute; đầy đủ giấy tờ, h&oacute;a đơn nguồn gốc xuất xứ r&otilde; r&agrave;ng, được bảo h&agrave;nh ch&iacute;nh h&atilde;ng từ 1 - 3 năm. Ngo&agrave;i ra, khi mua&nbsp;PC Văn Ph&ograve;ng&nbsp;tại Zafes Computer, qu&yacute; kh&aacute;ch h&agrave;ng c&ograve;n được cung cấp c&aacute;c dịch vụ số một k&egrave;m theo:</p>\n<ul>\n<li><em>Tặng ngay bộ Window v&agrave; Office bản quyền.</em></li>\n<li><em>Bảo h&agrave;nh tận nơi tại nội th&agrave;nh H&agrave; Nội v&agrave; TP.Hồ Ch&iacute; Minh&nbsp;</em></li>\n<li><em>Miễn ph&iacute; lắp đặt - Giao h&agrave;ng to&agrave;n quốc .</em></li>\n<li><em>Miễn ph&iacute; l&ecirc;n đời v&agrave; trải nghiệm sản phẩm trong v&ograve;ng 15 ng&agrave;y</em></li>\n<li><em>Cung cấp h&oacute;a đơn, chứng từ đầy đủ hợp lệ</em></li>\n</ul>',10,'/uploads/images/1743678269196.jpg,/uploads/images/1743678269196.jpg','c0dfc09e-a202-4884-b29b-6cbaf38c5fe1',222,'pc','active','2025-04-03 11:04:29','2025-04-03 11:04:29',NULL),('1b9fa7dc-b315-4985-808e-b1f4b181c88b','Nguồn Máy Tính ANTEC CUPRUM STRIKE CSK750 (750w, 80 Plus Bronze)',1800000,'<h2>Nguồn Máy Tính ANTEC CUPRUM STRIKE CSK750 (750w, 80 Plus Bronze)</h2>\n<p><strong><a href=\"\\&quot;https:/pcmarket.vn/psu-nguon-may-tinh.html\\&quot;\" rel=\"noopener noreferrer\">Nguồn máy tính</a></strong> Antec CUPRUM STRIKE CSK750H 750W mới nhất của Antec mang trong mình sự kết hợp hoàn hảo giữa hiệu suất, độ tin cậy và chất lượng. Được bảo hành trong ba năm và được chứng nhận 80 PLUS® BRONZE, CSK Bronze hứa hẹn đem đến nguồn điện an toàn và đáng tin cậy cho hệ thống của bạn.</p>\n<p><img src=\"\\&quot;https:/pcmarket.vn/media/lib/23-12-2023/pcm-nguon-may-tinh-antec-csk-750-mota_1.jpg\\&quot;\" alt=\"\\&quot;Nguồn\" width=\"\\&quot;1000\\&quot;\" height=\"\\&quot;490\\&quot;\" loading=\"lazy\" /></p>\n<p> </p>\n<h3><strong>Thiết Kế Hiện Đại và Kích Thước Tiêu Chuẩn</strong></h3>\n<p>ANTEC CUPRUM STRIKE CSK750 có kích thước chuẩn ATX (140 × 150 × 86 mm), phù hợp với hầu hết các hộp máy tính trung tâm. Với quạt tản nhiệt được tích hợp và logo chữ A màu vàng, nó không chỉ mang lại hiệu năng mà còn tạo điểm nhấn thú vị cho hệ thống của bạn.Hệ thống dây semi mô-đun cho phép bạn sử dụng các loại cáp bạn cần, giúp bạn tiết kiệm không gian và giảm sự lộn xộn, đồng thời cải thiện luồng không khí.</p>\n<p><img src=\"\\&quot;https:/pcmarket.vn/media/lib/23-12-2023/pcm-nguon-may-tinh-antec-csk-750-mota_2.jpg\\&quot;\" alt=\"\\&quot;Nguồn\" width=\"\\&quot;1000\\&quot;\" loading=\"lazy\" /></p>\n<h3><strong>Công Suất Đáng Tin Cậy</strong></h3>\n<p>Nguồn Máy Tính ANTEC CUPRUM STRIKE CSK750H cung cấp công suất lên đến 750W, đáp ứng nhu cầu của các hệ thống phức tạp. Với các cổng kết nối đa dạng, bạn có linh hoạt trong việc cấp nguồn cho các linh kiện khác nhau của hệ thống.</p>\n<p><img src=\"\\&quot;https:/pcmarket.vn/media/lib/23-12-2023/pcm-nguon-may-tinh-antec-csk-750-mota_3.jpg\\&quot;\" alt=\"\\&quot;Nguồn\" width=\"\\&quot;1000\\&quot;\" loading=\"lazy\" /></p>\n<h3><strong>Quạt Im Lặng Đảm Bảo Hiệu Suất</strong></h3>\n<p><a href=\"\\&quot;https:/pcmarket.vn/tan-nhiet-cooling.html\\&quot;\" rel=\"noopener noreferrer\"><strong>Quạt tản nhiệt</strong></a> 120mm hoạt động êm ái không chỉ giúp làm mát hiệu quả mà còn đảm bảo tuổi thọ của nguồn máy tính. Điều này mang lại sự yên tĩnh cho hệ thống của bạn, giúp tận hưởng trải nghiệm máy tính một cách tĩnh lặng.</p>\n<p><img src=\"\\&quot;https:/pcmarket.vn/media/lib/23-12-2023/pcm-nguon-may-tinh-antec-csk-750-mota_5.jpg\\&quot;\" alt=\"\\&quot;pcm-nguon-may-tinh-antec-csk-750-mota_5\\&quot;\" width=\"\\&quot;1000\\&quot;\" loading=\"lazy\" /></p>\n<h3><strong>Antec: Nhà Sản Xuất Có Uy Tín Lâu Đời</strong></h3>\n<p>Antec, Inc. đã ghi dấu ấn trong ngành công nghiệp linh kiện và phụ kiện máy tính kể từ năm 1986. Với hơn 35 năm kinh nghiệm, Antec đã sản xuất và tiêu thụ hơn một triệu sản phẩm tại Hoa Kỳ. Đội ngũ Antec cũng đã phục vụ các nhà xây dựng hệ thống, VAR và tích hợp với cam kết về chất lượng.</p>\n<p><img src=\"\\&quot;https:/pcmarket.vn/media/lib/23-12-2023/pcm-nguon-may-tinh-antec-csk-750-mota_4.jpg\\&quot;\" alt=\"\\&quot;pcm-nguon-may-tinh-antec-csk-750-mota_6\\&quot;\" width=\"\\&quot;1000\\&quot;\" loading=\"lazy\" /></p>\n<p><img src=\"\\&quot;https:/pcmarket.vn/media/lib/23-12-2023/pcm-nguon-may-tinh-antec-csk-750-mota_6.jpg\\&quot;\" alt=\"\\&quot;pcm-nguon-may-tinh-antec-csk-750-mota_7\\&quot;\" width=\"\\&quot;1040\\&quot;\" height=\"\\&quot;1478\\&quot;\" loading=\"lazy\" /></p>\n<p>Bộ Nguồn Máy Tính ANTEC CUPRUM STRIKE CSK750H của Antec không chỉ đáng tin cậy mà còn mang lại hiệu suất vượt trội và sự yên tĩnh cho hệ thống của bạn. Với thiết kế hiện đại và kinh nghiệm lâu đời của Antec, bạn có thể yên tâm sử dụng sản phẩm này trong nhiều năm tới.</p>',0,'/uploads/images/1747223300974.jpg,/uploads/images/1747223300974.jpg','751258d9-4091-4ce5-9b7e-ffb7a8513f34',1000,'power','active','2025-05-14 11:48:20','2026-05-08 20:34:57',NULL),('1c790b94-1a0f-4900-b4e1-720aad70b090','1/5  Ổ CỨNG SSD PNY CS1031 500GB M.2 2280 PCIE NVME GEN 3X4 (ĐỌC 2200MB/S - GHI 1200MB/S)',2390000,'<div>\n<p>THÔNG SỐ KỸ THUẬT</p>\n<div>\n<table border=\"1\">\n<tbody>\n<tr>\n<td><strong>Thương hiệu</strong></td>\n<td>PNY</td>\n</tr>\n<tr>\n<td><strong>Mã part</strong></td>\n<td>CS1031</td>\n</tr>\n<tr>\n<td><strong>Loại</strong></td>\n<td>Internal Solid State Drive (SSD)</td>\n</tr>\n<tr>\n<td><strong>Phân khúc</strong></td>\n<td>Consumer</td>\n</tr>\n<tr>\n<td><strong>Chuẩn kích cỡ</strong></td>\n<td>M.2 2280</td>\n</tr>\n<tr>\n<td><strong>Dung lượng</strong></td>\n<td>500GB</td>\n</tr>\n<tr>\n<td><strong>Giao tiếp</strong></td>\n<td>PCIe NVMe 3x4</td>\n</tr>\n<tr>\n<td><strong>Tốc độ đọc tối đa</strong></td>\n<td>Up to 2200 MBps</td>\n</tr>\n<tr>\n<td><strong>Tốc độ ghi tối đa</strong></td>\n<td>Up to 1200 MBps</td>\n</tr>\n<tr>\n<td><strong>MTBF</strong></td>\n<td>2,000,000 giờ</td>\n</tr>\n<tr>\n<td><strong>Kích thước</strong></td>\n<td>22mm x 80mm x 2 mm</td>\n</tr>\n<tr>\n<td><strong>Cân nặng</strong></td>\n<td>6,6g</td>\n</tr>\n</tbody>\n</table>\n</div>\n<div><a rel=\"noopener noreferrer\">THU GỌN</a></div>\n</div>\n<div>\n<p>MÔ TẢ SẢN PHẨM</p>\n<div>\n<h2>Ổ CỨNG SSD PNY CS1031 500GB M.2 2280 PCIE NVME GEN 3X4 (ĐỌC 2200MB/S - GHI 1200MB/S)</h2>\n<p><br />Ổ cứng SSD CS1031 M.2 PCIe Gen3 x4 NVMe của PNY là giải pháp nâng cấp máy tính để mang đến hiệu năng siêu cao khi được trang bị chuẩn NVMe PCIe Gen 3 x4. Với hiệu năng gấp 3 đến 4 lần một ổ SSD Sata, giúp tải dữ liệu nhanh hơn, tiêu thụ ít điện hơn và ít tỏa nhiệt hơn, với tốc độ đọc ghi lên đến 1700MB/s và 1500MB/s, cho độ bền cao và giúp tăng hiệu suất cùng khả năng lưu trữ.</p>\n<p><img src=\"https://pcmarket.vn/media/lib/04-05-2024/79060_o_cung_ssd_pny_cs1031_500gb_m__1_mota.jpg\" alt=\"\" loading=\"lazy\" /> </p>\n<h3>SSD M.2 NVMe  3x4</h3>\n<p> <img src=\"https://pcmarket.vn/media/lib/04-05-2024/79060_o_cung_ssd_pny_cs1031_500gb_m__1_mota_2.jpg\" alt=\"\" width=\"1000\" loading=\"lazy\" /></p>\n<p>Với tốc độ đọc ghi đáng kinh ngạc, ổ cứng SSD PNY CS1031 M.2 PCIe Gen3 x4 NVMe sẽ tăng hiệu suất tổng thể của máy tính lên mức tối đa, giúp bạn xử lý công việc cực kỳ nhanh chóng.Lý tưởng cho các hệ thống có dung lượng hạn chế<br />Dễ dàng tích hợp vào các thiết bị có khe cắm M.2. Lý tưởng cho Laptop và PC cỡ nhỏ.</p>\n</div>\n<div> </div>\n</div>',0,'/uploads/images/b1f22b29-b9d6-4072-af6b-ccad6487dd95.jpg,/uploads/images/e66e9aaa-73ff-4c5c-9518-672be10f83fc.jpg,/uploads/images/ea0e23e7-6c7e-46b7-90ca-c81a8f265854.jpg','751258d9-4091-4ce5-9b7e-ffb7a8513f34',0,'ssd','active','2026-05-08 20:10:19','2026-05-08 20:10:19',NULL),('1d7b4e99-f9d5-423d-adbd-fb532522de8d','CPU Intel Core i5-13600KF (14 nhân 20 luồng ,Up to 5.1GHz, 24MB )',8900000,'<p>THÔNG SỐ KỸ THUẬT</p>\n<div>\n<table border=\"1\">\n<tbody>\n<tr>\n<td>Sản phẩm </td>\n<td>CPU - Bộ vi xử lý</td>\n</tr>\n<tr>\n<td>Hãng sản xuất</td>\n<td>Intel</td>\n</tr>\n<tr>\n<td>Loại CPU</td>\n<td>Dành cho máy bàn</td>\n</tr>\n<tr>\n<td>Thế hệ</td>\n<td>Core i5 Thế hệ thứ 13</td>\n</tr>\n<tr>\n<td>Tên gọi</td>\n<td>Core i5-13600KF</td>\n</tr>\n<tr>\n<td>CHI TIẾT</td>\n</tr>\n<tr>\n<td>Socket</td>\n<td>FCLGA 1700</td>\n</tr>\n<tr>\n<td>Tên thế hệ</td>\n<td>Raptor Lake</td>\n</tr>\n<tr>\n<td>Số nhân</td>\n<td>14</td>\n</tr>\n<tr>\n<td>Số luồng</td>\n<td>20</td>\n</tr>\n<tr>\n<td>Tốc độ cơ bản</td>\n<td>Tần số turbo tối đa: 5.10 GHz</td>\n</tr>\n<tr>\n<td>Tần số Turbo tối đa của P-core: 5.10 GHz</td>\n</tr>\n<tr>\n<td>Tần số Turbo tối đa của E-core: 3.9 GHz</td>\n</tr>\n<tr>\n<td>Tần số Cơ sở của P-core: 3.50 GHz</td>\n</tr>\n<tr>\n<td>Tần số Cơ sở E-core: 2.6 GHz</td>\n</tr>\n<tr>\n<td>Cache</td>\n<td>24MB</td>\n</tr>\n<tr>\n<td>Total L2 Cache: 20MB</td>\n</tr>\n<tr>\n<td>Hỗ trợ bộ nhớ</td>\n<td>Tối đa 128 GB</td>\n</tr>\n<tr>\n<td>DDR4 3200 MHz</td>\n</tr>\n<tr>\n<td>DDR5 5600 MHz</td>\n</tr>\n<tr>\n<td>Hỗ trợ số kênh bộ nhớ</td>\n<td>2</td>\n</tr>\n<tr>\n<td>Nhân đồ họa tích hợp</td>\n<td> </td>\n</tr>\n<tr>\n<td>Phiên bản PCI Express</td>\n<td>5.0 and 4.0</td>\n</tr>\n<tr>\n<td>Số lane PCI Express</td>\n<td>Up to 1x16+4, 2x8+4</td>\n</tr>\n<tr>\n<td>TDP</td>\n<td>Công suất cơ bản: 125W</td>\n</tr>\n<tr>\n<td>Công suất tối đa: 181W</td>\n</tr>\n</tbody>\n</tab